scwin.f_downExcelSheet = async function () {
  let cntRow = ds_houseblList.getRowCount();
  if (cntRow != 0) {
    let cfrm = await $c.win.confirm($p, "House B/L List를 EXCEL로 다운로드 받으시겠습니까?");
    if (cfrm) {
      $c.data.downloadGridViewExcel($p, gr_houseblList, {
        fileName: "House BL List.xlsx",
        sheetName: "House BL List"
      });
    }
  } else {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_WRN_002);
  }
};
